// ============================================================================
// Helper functions
// ============================================================================

export function getDestinationBySlug(slug: string): Destination | undefined {
  return destinations.find((d) => d.slug === slug);
}

export function getAllSlugs(): string[] {
  return destinations.map((d) => d.slug);
}

export function getDestinationsByContinent(continent: string): Destination[] {
  return destinations.filter((d) => d.continent === continent);
}

export function getRelatedDestinations(
  slug: string,
  limit = 6
): Destination[] {
  const current = getDestinationBySlug(slug);
  if (!current) return destinations.slice(0, limit);

  const currentTags = new Set(current.tags);

  return destinations
    .filter((d) => d.slug !== slug)
    .map((d) => {
      const sharedTags = d.tags.filter((t) => currentTags.has(t)).length;
      const sameContinent = d.continent === current.continent ? 2 : 0;
      const similarBudget = d.stats.budgetLevel === current.stats.budgetLevel ? 1 : 0;
      return { destination: d, score: sharedTags * 3 + sameContinent + similarBudget };
    })
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((r) => r.destination);
}

export function getDestinationsByTag(
  tag: string,
  excludeSlug?: string,
  limit = 6
): Destination[] {
  return destinations
    .filter((d) => d.tags.includes(tag) && d.slug !== excludeSlug)
    .slice(0, limit);
}

/**
 * Find the previous and next destination in alphabetical order within
 * the same continent. At continent boundaries the prev/next slot is
 * null. Used for the prev/next navigation block on detail pages.
 */
export function getPrevNextDestinations(
  slug: string,
  locale: Locale = "en"
): { prev: Destination | null; next: Destination | null } {
  const current = getDestinationBySlug(slug);
  if (!current) return { prev: null, next: null };
  const sameContinent = destinations
    .filter((d) => d.continent === current.continent)
    .sort((a, b) => a.name[locale].localeCompare(b.name[locale]));
  const idx = sameContinent.findIndex((d) => d.slug === slug);
  if (idx === -1) return { prev: null, next: null };
  return {
    prev: idx > 0 ? sameContinent[idx - 1] : null,
    next: idx < sameContinent.length - 1 ? sameContinent[idx + 1] : null,
  };
}
